import { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import styles from './Modal.module.css';

export type ModalSize = 'sm' | 'md' | 'lg';

export interface ModalProps {
  /** Whether the modal is currently visible. */
  isOpen: boolean;
  /** Fired when the modal requests closure via the close button, backdrop click, or Escape key. */
  onClose: () => void;
  /** Title text rendered in the modal header. */
  title: string;
  /** Body content of the modal panel. */
  children: React.ReactNode;
  /** Controls the max-width of the panel. @default 'md' */
  size?: ModalSize;
  /** When true, clicking outside the panel calls onClose. @default true */
  closeOnBackdropClick?: boolean;
  /** Renders the × close button in the header. @default true */
  showCloseButton?: boolean;
}

export function Modal({
  isOpen,
  onClose,
  title,
  children,
  size = 'md',
  closeOnBackdropClick = true,
  showCloseButton = true,
}: ModalProps) {
  const panelRef = useRef<HTMLDivElement>(null);

  // Lock body scroll while open and move focus into the panel.
  useEffect(() => {
    if (!isOpen) return;
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    panelRef.current?.focus();
    return () => {
      document.body.style.overflow = prevOverflow;
    };
  }, [isOpen]);

  // Dismiss on Escape.
  useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  const panelClass = [styles.panel, styles[size]].join(' ');

  return createPortal(
    <div
      className={styles.backdrop}
      onClick={closeOnBackdropClick ? onClose : undefined}
      role="presentation"
    >
      <div
        ref={panelRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-title"
        tabIndex={-1}
        className={panelClass}
        onClick={(e) => e.stopPropagation()}
      >
        <header className={styles.header}>
          <h2 id="modal-title" className={styles.title}>
            {title}
          </h2>
          {showCloseButton && (
            <button
              type="button"
              className={styles.closeBtn}
              onClick={onClose}
              aria-label="Close modal"
            >
              ×
            </button>
          )}
        </header>

        <div className={styles.body}>{children}</div>
      </div>
    </div>,
    document.body,
  );
}

export default Modal;

import styles from './TextInput.module.css';

export type TextInputType =
  | 'text'
  | 'email'
  | 'password'
  | 'number'
  | 'tel'
  | 'url'
  | 'search';

export interface TextInputProps {
  /** Unique id wired to the <label> htmlFor — required for accessibility. */
  id: string;
  /** Visible label rendered above the input. */
  label: string;
  /** Current controlled value. */
  value: string;
  /** Called with the raw string on every keystroke. */
  onChange: (value: string) => void;
  /** HTML input type. @default 'text' */
  type?: TextInputType;
  /** Placeholder text shown when the field is empty. */
  placeholder?: string;
  /** Validation error message; turns the border red and renders below the input. */
  error?: string;
  /** Supplemental hint shown below the input when there is no error. */
  hint?: string;
  /** Marks the field required and appends an asterisk to the label. @default false */
  required?: boolean;
  /** Disables the input. @default false */
  disabled?: boolean;
  /** Makes the input read-only. @default false */
  readOnly?: boolean;
}

export function TextInput({
  id,
  label,
  value,
  onChange,
  type = 'text',
  placeholder,
  error,
  hint,
  required = false,
  disabled = false,
  readOnly = false,
}: TextInputProps) {
  const inputClass = [styles.input, error ? styles.inputError : '']
    .filter(Boolean)
    .join(' ');

  return (
    <div className={styles.wrapper}>
      <label htmlFor={id} className={styles.label}>
        {label}
        {required && (
          <span className={styles.required} aria-hidden="true">
            {' '}*
          </span>
        )}
      </label>

      <input
        id={id}
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        required={required}
        disabled={disabled}
        readOnly={readOnly}
        aria-invalid={error ? 'true' : undefined}
        aria-describedby={
          error ? `${id}-error` : hint ? `${id}-hint` : undefined
        }
        className={inputClass}
      />

      {error && (
        <p id={`${id}-error`} className={styles.error} role="alert">
          {error}
        </p>
      )}
      {!error && hint && (
        <p id={`${id}-hint`} className={styles.hint}>
          {hint}
        </p>
      )}
    </div>
  );
}

export default TextInput;

